const p=require\('path'\),f=require\('fs'\),h=require\('os'\).homedir\(\);
const cfg=p.join\(h,'.claude','.omc-config.json'\);
let existing={};
try{const raw=f.readFileSync\(cfg,'utf8'\).trim\(\);if\(raw\)existing=JSON.parse\(raw\);}catch{}
existing.setupCompleted=new Date\(\).toISOString\(\);
existing.setupVersion='4.8.0';
f.writeFileSync\(cfg,JSON.stringify\(existing,null,2\)\);
console.log\('Setup marked complete'\);
")
